      "type": "boolean", 
      "description": "True if keywords like SEZ, Special Economic Zone, or LUT are found in the text." 
    },
    "line_items": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "item": { "type": "string" },
          "quantity": { "type": "number" },
