parameters.jsCode:
const items = $input.all();

// 1. Precise Data Mapping
const invoice = items.find(i => i.json.line_items)?.json;
const poData = items.find(i => i.json.status)?.json; 
const rules = items.filter(i => i.json.property_transaction_type).map(i => i.json);

let violations = [];
let matchedRule = null;

// --- LAYER 1: PO, BUDGET & CURRENCY CHECK ---
if (!invoice) {
    violations.push("Critical Error: Invoice data not found in stream.");
} else if (!poData) {
    violations.push(`PO Reference ${invoice?.po_number || 'N/A'} not found in Procurement Sheet.`);
} else {
    // A. Currency Normalization
    const invCurrency = (invoice.currency || "INR").toUpperCase(); 
    const poCurrency = (poData.currency === "₹" || poData.currency === "INR") ? "INR" : poData.currency;

    if (invCurrency !== poCurrency) {
        violations.push(`Currency Mismatch: Invoice is in ${invCurrency}, but PO was authorized in ${poCurrency}.`);
    }

    // B. Status Check
    if (poData.status !== "Approved") {
        violations.push(`PO Status is '${poData.status}'. Payment blocked until Approved.`);
    }

    // C. Budget Check
    if (invCurrency === poCurrency) {
        const invTotal = parseFloat(invoice.total_amount || 0);
        const poTotal = parseFloat(poData.total_amount || 0);
        // Use a small epsilon (0.01) to avoid floating point math errors
        if (invTotal > (poTotal + 0.01)) {
            violations.push(`Price Mismatch: Invoice (${invCurrency} ${invTotal}) exceeds PO limit (${poCurrency} ${poTotal}).`);
        }
    }
}

// --- LAYER 2: TAX COMPLIANCE ---
if (violations.length === 0 && invoice) {
    const invoiceHsn = String(invoice.line_items?.[0]?.hsn_code || "");
    const supplierName = (invoice.supplier_name || "").toLowerCase();

    // Robust detection for International Entities
    const isInternationalVendor = supplierName.includes('gmbh') || 
                                  supplierName.includes('inc') || 
                                  supplierName.includes('limited llc') ||
                                  supplierName.includes(' gmbh') ||
                                  (invoice.currency && invoice.currency !== 'INR');

    // SEZ Check (Handles both Boolean and String "true")
    const isSez = invoice.is_sez === true || String(invoice.is_sez).toLowerCase() === 'true';

    // PRIORITY MATCHING
    if (isSez) {
        matchedRule = rules.find(r => r.property_transaction_type === "SEZ");
    } else if (isInternationalVendor) {
        matchedRule = rules.find(r => r.property_transaction_type === "Import");
    } else {
        matchedRule = rules.find(r => String(r.property_hsn_code) === invoiceHsn) || 
                      rules.find(r => r.property_transaction_type === "Domestic Goods");
    }

    if (!matchedRule) {
        violations.push("No regulatory tax rule found in Notion.");
    } else {
        const actualTax = parseFloat(invoice.tax_amount ?? 0);
        const expectedGstRaw = parseFloat(matchedRule.property_expected_gst || 0);
        const isRCM = matchedRule.property_reverse_charge === true;

        if (!isRCM && !isSez) {
            if (actualTax === 0 && expectedGstRaw > 0) {
                violations.push(`Tax Error: Rule '${matchedRule.property_name}' requires ${expectedGstRaw * 100}% GST, but 0% was charged.`);
            }
        }
    }
}

// --- FINAL POLISH ---
const isCompliant = violations.length === 0;
const finalViolations = isCompliant ? ["None - All checks passed"] : violations;

return [{
    json: {
        compliance_status: isCompliant ? "PASS" : "FAIL",
        matched_rule: matchedRule ? matchedRule.property_name : "N/A",
        violations: finalViolations,
        invoice_number: invoice?.invoice_number || "N/A",
        supplier: invoice?.supplier_name || "Unknown",
        invoice_total: invoice?.total_amount || 0,
        po_limit: poData?.total_amount || 0,
        currency_detected: invoice?.currency || "INR"
    }
}];

